  `total_area` decimal(10,2) DEFAULT NULL,
  `population` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `land_use` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `hazard_level` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Active',
  `is_visible` tinyint(1) NOT NULL DEFAULT '1',
  `agri_area` decimal(10,2) DEFAULT NULL,
  `residential_area` decimal(10,2) DEFAULT NULL,
  `commercial_area` decimal(10,2) DEFAULT NULL,
  `unidentified_area` decimal(10,2) DEFAULT NULL,
  `latitude` decimal(10,7) DEFAULT NULL,
  `longitude` decimal(10,7) DEFAULT NULL,
  `boundary` json DEFAULT NULL,
  `boundary_source` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `boundary_updated_at` timestamp NULL DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=80 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
